from ag2 import GroupChat
from ag2.utils import estimate_token_count

def monitor_context_window(chat: GroupChat):
    history = chat.messages
    total_tokens = sum(estimate_token_count(msg.content) for msg in history)
    max_tokens = 120000  # GPT-4 limit

    if total_tokens > max_tokens * 0.8:
        print(f'⚠️  Context window at {total_tokens/max_tokens*100:.1f}% capacity')
        return {'warning': 'Context overflow imminent', 'tokens': total_tokens}
    return {'status': 'healthy', 'tokens': total_tokens}

from ag2 import GroupChat
import numpy as np
from sentence_transformers import SentenceTransformer

model = SentenceTransformer('all-MiniLM-L6-v2')

def detect_drift(chat: GroupChat):
    if len(chat.messages) < 10:
        return {'drift_score': 0}

    recent_msgs = [m.content for m in chat.messages[-5:]]
    early_msgs = [m.content for m in chat.messages[:5]]

    recent_emb = np.mean([model.encode(msg) for msg in recent_msgs], axis=0)
    early_emb = np.mean([model.encode(msg) for msg in early_msgs], axis=0)

    similarity = np.dot(recent_emb, early_emb) / (np.linalg.norm(recent_emb) * np.linalg.norm(early_emb))
    drift_score = 1 - similarity

    if drift_score > 0.4:
        return {'drift_score': drift_score, 'alert': 'High topic drift detected'}
    return {'drift_score': drift_score}

from ag2 import GroupChat
from collections import Counter

def track_speaker_dominance(chat: GroupChat):
    speakers = [msg.sender for msg in chat.messages[-20:] if hasattr(msg, 'sender')]
    speaker_counts = Counter(speakers)
    total_msgs = len(speakers)

    if total_msgs == 0:
        return {'dominance_ratio': 0}

    max_dominance = max(speaker_counts.values()) / total_msgs

    if max_dominance > 0.5:
        dominant = speaker_counts.most_common(1)[0][0]
        return {'dominance_ratio': max_dominance, 'warning': f'{dominant} dominates conversation'}

    return {'dominance_ratio': max_dominance, 'status': 'balanced'}

