from ag2 import GroupChatManager
from ag2.core import register_message_hook

class ContextPruner:
    def __init__(self, max_tokens=100000):
        self.max_tokens = max_tokens
        self.relevant_msgs = []

    @register_message_hook
    def prune_context(self, chat: GroupChatManager, message):
        # Add new message
        self.relevant_msgs.append(message)

        # Estimate tokens
        total_tokens = sum(estimate_token_count(msg.content) for msg in self.relevant_msgs)

        if total_tokens > self.max_tokens:
            # Sort by recency and relevance score
            scored_msgs = sorted(self.relevant_msgs, 
                               key=lambda m: (m.timestamp, self._relevance_score(m)), reverse=True)
            self.relevant_msgs = scored_msgs[:int(self.max_tokens * 0.9 / 500)]

        chat.messages = self.relevant_msgs
        return message

    def _relevance_score(self, msg):
        # Simple heuristic: longer messages, from critics, recent
        return len(msg.content) * (0.1 if 'error' in msg.content.lower() else 1)

